import{_ as e,o,c as r,a2 as i}from"./chunks/framework.DCVnL8g5.js";const h=JSON.parse('{"title":"Manual de Arquitectura Hexagonal","description":"","frontmatter":{},"headers":[],"relativePath":"full-stack/arquitectura/hexagonal/01-introduccion-y-puertos-adaptadores.md","filePath":"full-stack/arquitectura/hexagonal/01-introduccion-y-puertos-adaptadores.md","lastUpdated":1782521464000}'),t={name:"full-stack/arquitectura/hexagonal/01-introduccion-y-puertos-adaptadores.md"};function s(n,a,l,d,c,p){return o(),r("div",null,[...a[0]||(a[0]=[i(`<h1 id="manual-de-arquitectura-hexagonal" tabindex="-1">Manual de Arquitectura Hexagonal <a class="header-anchor" href="#manual-de-arquitectura-hexagonal" aria-label="Permalink to &quot;Manual de Arquitectura Hexagonal&quot;">​</a></h1><p>La arquitectura hexagonal organiza una aplicacion alrededor de su dominio y sus casos de uso. El exterior se conecta mediante puertos y adaptadores, de forma que HTTP, bases de datos, colas o proveedores externos no dicten el diseno interno.</p><p>Tambien se conoce como ports and adapters.</p><h2 id="capitulos-previstos" tabindex="-1">Capitulos previstos <a class="header-anchor" href="#capitulos-previstos" aria-label="Permalink to &quot;Capitulos previstos&quot;">​</a></h2><ol><li><a href="./01-introduccion-y-puertos-adaptadores">Introduccion y puertos adaptadores</a></li><li><a href="./02-dominio-y-casos-de-uso">Dominio y casos de uso</a></li><li><a href="./03-adaptadores-de-entrada">Adaptadores de entrada</a></li><li><a href="./04-adaptadores-de-salida">Adaptadores de salida</a></li><li><a href="./05-testing">Testing</a></li><li><a href="./06-aplicacion-practica">Aplicacion practica</a></li><li><a href="./07-puertos-de-entrada-y-salida">Puertos de entrada y salida</a></li><li><a href="./08-transacciones-errores-y-eventos">Transacciones errores y eventos</a></li><li><a href="./09-integracion-con-frameworks">Integracion con frameworks</a></li><li><a href="./10-observabilidad-y-operacion">Observabilidad y operacion</a></li><li><a href="./11-migracion-desde-arquitectura-por-capas">Migracion desde arquitectura por capas</a></li><li><a href="./12-proyecto-final">Proyecto final</a></li></ol><h2 id="idea-central" tabindex="-1">Idea central <a class="header-anchor" href="#idea-central" aria-label="Permalink to &quot;Idea central&quot;">​</a></h2><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>              HTTP Controller</span></span>
<span class="line"><span>                    |</span></span>
<span class="line"><span>CLI Command -&gt; Puerto de entrada -&gt; Caso de uso -&gt; Puerto de salida -&gt; Repositorio SQL</span></span>
<span class="line"><span>                    |                                  |</span></span>
<span class="line"><span>             Event Consumer                            -&gt; Cliente externo</span></span></code></pre></div><p>El caso de uso no sabe si viene de HTTP, CLI, cron o Kafka. Tampoco sabe si guarda en PostgreSQL, MongoDB o un servicio externo.</p><h2 id="puertos" tabindex="-1">Puertos <a class="header-anchor" href="#puertos" aria-label="Permalink to &quot;Puertos&quot;">​</a></h2><p>Un puerto es un contrato.</p><ul><li>Puerto de entrada: lo que la aplicacion ofrece.</li><li>Puerto de salida: lo que la aplicacion necesita.</li></ul><h2 id="adaptadores" tabindex="-1">Adaptadores <a class="header-anchor" href="#adaptadores" aria-label="Permalink to &quot;Adaptadores&quot;">​</a></h2><p>Un adaptador conecta un puerto con tecnologia real.</p><ul><li>Entrada: REST controller, GraphQL resolver, job, consumer.</li><li>Salida: repositorio SQL, cliente HTTP, cache, cola, filesystem.</li></ul><h2 id="beneficio-principal" tabindex="-1">Beneficio principal <a class="header-anchor" href="#beneficio-principal" aria-label="Permalink to &quot;Beneficio principal&quot;">​</a></h2><p>La tecnologia se vuelve sustituible. El dominio y los casos de uso quedan protegidos de decisiones externas.</p>`,16)])])}const f=e(t,[["render",s]]);export{h as __pageData,f as default};
